class EditSessionPage extends HookConsumerWidget {
  const EditSessionPage({required this.originalSession, super.key});

  final Session originalSession;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final isSingleTeam = useSingleTeamCheck();
    final titleController =
        useTextEditingController(text: originalSession.title);
    final noteController = useTextEditingController(text: originalSession.note);
    final locationController =
        useTextEditingController(text: originalSession.location);

    useListenable(titleController);
    useListenable(noteController);
    useListenable(locationController);

    final handleOperation = useOperation();
    final checkSessionEditAccess = useSessionEditAccess();
    final isValid = useState(false);

    final playerList = ref.watch(allPlayersProvider);
    final selectedPlayer = useState<Player?>(null);

    useEffect(
      () {
        final atLeastOneParamChanged =
            titleController.text != originalSession.title ||
                noteController.text != originalSession.note ||
                locationController.text != originalSession.location ||
                selectedPlayer.value?.id != originalSession.playerId;

        // Check if we have a valid player selection
        // selectedPlayer.value will be null when "Select Player" is chosen
        final hasValidPlayer = selectedPlayer.value != null;

        isValid.value = hasValidPlayer && atLeastOneParamChanged;
        return null;
      },
      [
        titleController.text,
        noteController.text,
        locationController.text,
        selectedPlayer.value,
      ],
    );

    return Scaffold(
      appBar: CustomAppBar(
        title: context.l10n.edit_session_page__title_edit,
        isBackNavigation: true,
      ),
      body: SafeArea(
        child: playerList.when(
          data: (players) {
            useEffectOnce(() {
              WidgetsBinding.instance.addPostFrameCallback((_) {
                selectedPlayer.value = players.firstWhereOrNull(
                  (p) => p.id == originalSession.playerId,
                );
              });
              return null;
            });

            final runEdit = useSingleAction<void>(asyncCallback: (_) async {
              final userId = ref.read(profileStorageProvider).getUserId();
              final isAccessible =

  final isAccessible =
      await checkSessionEditAccess(originalSession, userId!);
  if (!isAccessible) return;

  await handleOperation(
    operation: ref
        .read(sessionListControllerProvider.notifier)
        .editSession(
          sessionId: originalSession.id!,
          note: noteController.text,
          location: locationController.text,
          title: titleController.text,
          playerId: selectedPlayer.value!.id!,
        ),
    onSucceeded: (updatedSession) {
      Navigator.of(context).pop(updatedSession);
      return context.l10n.edit_session_page__edit_session_succeeded;
    },
    onFailed: (error) {
      final preamble =
          context.l10n.edit_session_page__edit_session_failed;
      return '$preamble: ${error.translate(context.l10n)}';
    },
    shouldSendErrorLog: (failure) =>
        failure is! UnprocessableEntityFailure,
  );
});

return EditPageLayout(
  onPressed: isValid.value ? runEdit : null,
  children: [
    const Gap(16),
    CustomTextFormField(
      controller: titleController,
      hintText: context.l10n.edit_session_page__title_hint,
      maxLength: InputMaxLengths.sessionTitle,
      onChanged: (text) {},
    ),
    if (!isSingleTeam) ...[
      const Gap(24),
      SearchableDropdownMenu<Player>(
        value: selectedPlayer.value,
        itemList: players,
        itemBuilder: (player) => Text(player.name ?? ''),
        displayString: (player) => player.name ?? '',
        hintText: context.l10n.edit_session_page__player_hint,
        onChanged: (player) {
          selectedPlayer.value = player;
        },
      ),

input.old_string:
        icon: const Icon(Icons.settings),
      ),
  ],
  bottom: PreferredSize(
    preferredSize: const Size.fromHeight(24),
    child: Padding(
      padding: HomePage.bodyPadding,
      child: SessionTabBar(controller: tabController),
    ),
  ),
),

